<template>
  <div class="content">
    <div class="category">
      <!-- <div class="category_item category_item-active">全部商品</div> -->
      <div
        :class="{'category_item': true, 'category_item-active': currentTab === item.tab}"
        v-for="(item, index) in categories"
        :key="index"
        @click="handleTabClick(item.tab)"
      >{{ item.name }}</div>
    </div>
    <div class="product">
      <div
        class="product_item"
        v-for="item in list"
        :key="item._id"
      >
        <img :src="item.imgUrl" />
        <div class="product_item_detail">
          <h4 class="product_item_title">{{ item.name }}</h4>
          <p class="product_item_sales">月售 {{ item.sales }} 件</p>
          <p class="product_item_price">
            <span class="product_item_yen">&yen;</span>
            {{ item.price }}
            <span class="product_item_origin">&yen;{{ item.oldPrice }}</span>
          </p>
        </div>
        <div class="product_number">
          <span
            class="product_number_minus"
            @click="changeCartItem(shopId, item._id, item, -1, shopName)"
          >-</span>
          {{ getProductCartCount(shopId, item._id) }}
          <span
            class="product_number_plus"
            @click="changeCartItem(shopId, item._id, item, 1, shopName)"
          >+</span>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { reactive, ref, toRefs, watchEffect } from 'vue'
import { useRoute } from 'vue-router'
import { useStore } from 'vuex'
import { get } from '../../utils/request'
import { useCommonCartEffect } from '../../effects/cartEffects'

const categories = [
  { name: '全部商品', tab: 'all' },
  { name: '秒杀', tab: 'seckill' },
  { name: '新鲜水果', tab: 'fruit' }
]

const useTabEffect = () => {  // Tab 切换相关的逻辑
  const currentTab = ref(categories[0].tab)
  const handleTabClick = (tab) => {
    currentTab.value = tab
  }

  return { currentTab, handleTabClick }
}

const useCurrentListEffect = (currentTab, shopId) => {  // 列表内容相关逻辑
  const content = reactive({ list: [] })
  const getContentData = async () => {
    const result = await get(`/api/shop/${shopId}/products`, { tab: currentTab.value })
    if (result?.errno === 0 && result?.data.length) {
      content.list = result.data   
    }
  }

  watchEffect(() => { getContentData() })

  const { list } = toRefs(content)
  return { list }
}

const useCartEffect = () => {  // 购物车相关逻辑
  const store = useStore()
  const { cartList, changeCartItemInfo } = useCommonCartEffect()
  const changeShopName = (shopId, shopName) => {
    store.commit('changeShopName', { shopId, shopName })
  }
  const changeCartItem = (shopId, productId, item, num, shopName) => {
    changeCartItemInfo(shopId, productId, item, num)
    changeShopName(shopId, shopName)
  }
  const getProductCartCount = (shopId, productId) => {
    return cartList?.[shopId]?.productList?.[productId]?.count || 0 
  }

  return { cartList, changeCartItem, getProductCartCount }
}

export default {
  name: 'Content',
  props: ['shopName'],
  setup() {
    const route = useRoute()
    const shopId = route.params.id
    const { currentTab, handleTabClick } = useTabEffect()
    const { list } = useCurrentListEffect(currentTab, shopId)
    const { cartList, changeCartItem, getProductCartCount } = useCartEffect()

    return { shopId, categories, currentTab, list, cartList, handleTabClick, changeCartItem, getProductCartCount }
  }
}
</script>

<style lang="scss" scoped>
  @import '../../styles/variables.scss';
  @import '../../styles/mixins.scss';
  .content {
    position: absolute;
    left: 0;
    right: 0;
    top: 1.5rem;
    bottom: .5rem;
    display: flex;
  }
  .category {
    width: .76rem;
    height: 100%;
    overflow-y: scroll;
    background: $search-bgColor;
    &_item {
      line-height: .4rem;
      text-align: center;
      font-size: .14rem;
      color: #333;
      &-active {
        background: $bgColor;
      }
    }
  }
  .product {
    flex: 1;
    overflow-y: scroll;
    &_item {
      display: flex;
      position: relative;
      padding: .12rem 0;
      margin: 0 .16rem;
      border-bottom: .01rem solid #f1f1f1;
      img {
        width: .68rem;
        height: .68rem;
        margin-right: .16rem;                                                                                                                                                           
      }
      &_detail {
        overflow: hidden;
      }
      &_title {
        margin: 0;
        line-height: .2rem;
        font-size: .14rem;
        color: #333;
        @include ellipses;
      }
      &_sales {
        margin: .06rem 0;
        font-size: .12rem;
        color: #333;
      }
      &_price {
        margin: 0;
        line-height: .2rem;
        font-size: .14rem;
        color: $hightlight-fontColor;
      }
      &_yen {
        font-size: .12rem;
      }
      &_origin {
        margin-left: .06rem;
        line-height: .2rem;
        font-size: .12rem;
        color: #999;
        text-decoration: line-through;
      }
      .product_number {
        position: absolute;
        right: 0;
        bottom: .12rem;
        &_minus,
        &_plus {
          display: inline-block;
          width: .2rem;
          height: .2rem;
          line-height: .16rem;
          border-radius: 50%;
          font-size: .2rem;
          text-align: center;
        }
        &_minus {
          border: .01rem solid $medium-fontColor;
          color: $medium-fontColor;
          margin-right: .05rem;
        }
        &_plus {
          margin-left: .05rem;
          color: $bgColor;
          background: $btn-bgColor;
        }
      }
    }
  }
</style>