import { computed } from 'vue'
import { useStore } from 'vuex'

export const useCommonCartEffect = (shopId) => {  // 购物车相关逻辑
  const store = useStore()
  const cartList = store.state.cartList
  const changeCartItemInfo = (shopId, productId, productInfo, num) => {
    store.commit('changeCartItemInfo', { shopId, productId, productInfo, num })
  }
  const productList = computed(() => {  // productList computed
    const productList = cartList[shopId]?.productList ?? {}
    const notEmptyProductList = {}
    for (let i in productList) {
      const product = productList[i]
      ;(product.count > 0)&&(notEmptyProductList[i] = product)
    }
    return notEmptyProductList
  })
  const shopName = computed(() => {  // shopName computed
    const shopName = cartList[shopId]?.shopName ?? ''
    return shopName
  })

  const calculations = computed(() => {
    const productList = cartList[shopId]?.productList
    // let total = 0
    // let price = 0
    // let allChecked = true
    const result = { total: 0, price: 0, allChecked: true }
    if (productList) {
      for (let i in productList) {
        const product = productList[i]
        result.total += product.count
        // if (product.check) {
        //   result.price += (product.count * product.price)
        // }
        // if (product.count > 0 && !product.check) {
        //   result.allChecked = false
        // }
        ;(product.check)&&(result.price += (product.count * product.price))
        ;(product.count > 0 && !product.check)&&(result.allChecked = false)
      }
    }
    result.price = result.price.toFixed(2)
    return result
  })

  return { cartList, productList, shopName, calculations, changeCartItemInfo }
}