<template>
  <div class="mask" v-if="showCart && calculations.total > 0" />
  <div class="cart">
    <div class="product" v-if="showCart && calculations.total > 0">
      <div class="product_header">
        <div
          class="product_header_all"
          @click="setCartItemsChecked(shopId)"
        >
          <span
            class="product_header_icon iconfont"
            v-html="calculations.allChecked ? '&#xe63a;' : '&#xe66c;'"
          />
          全选
        </div>
        <div class="product_header_clear">
          <span
            class="product_header_clear_btn"
            @click="cleanCartProducts(shopId)"
          >清空购物车</span>
        </div>
      </div>
      <div
        class="product_item"
        v-for="item in productList"
        :key="item._id"
      >
        <div
          class="product_item_checked iconfont"
          v-html="item.check ? '&#xe63a;' : '&#xe66c;'"
          @click="changeCartItemCheck(shopId, item._id)"
        ></div>
        <img :src="item.imgUrl" />
        <div class="product_item_detail">
          <h4 class="product_item_title">{{ item.name }}</h4>
          <p class="product_item_price">
            <span class="product_item_yen">&yen;</span>
            {{ item.price }}
            <span class="product_item_origin">&yen;{{ item.oldPrice }}</span>
          </p>
        </div>
        <div class="product_number">
          <span
            class="product_number_minus"
            @click="changeCartItemInfo(shopId, item._id, item, -1)"
          >-</span>
          {{ item.count || 0 }}
          <span
            class="product_number_plus"
            @click="changeCartItemInfo(shopId, item._id, item, 1)"
          >+</span>
        </div>
      </div>
    </div>
    <div class="check">
      <div class="check_icon">
        <img
          src="http://www.dell-lee.com/imgs/vue3/basket.png"
          @click="handleCartShowChange"
        />
        <div class="check_icon_tag">{{ calculations.total }}</div>
      </div>
      <div class="check_info">
        总计: <span class="check_info_price">&yen;{{ calculations.price }}</span>
      </div>
      <div class="check_btn" v-show="calculations.total > 0">
        <router-link :to="{ path: `/OrderConfirmation/${shopId}` }">
          去结算
        </router-link>
      </div>
    </div>
  </div>
</template>

<script>
import { ref } from "vue"
import { useStore } from "vuex"
import { useRoute } from "vue-router"
import { useCommonCartEffect } from "../../effects/cartEffects"

const useCartEffect = (shopId) => {  // 购物车相关逻辑
  const store = useStore()
  const { productList, calculations, changeCartItemInfo } = useCommonCartEffect(shopId)

  // const total = computed(() => {  // 数量总计 computed
  //   const productList = cartList[shopId]?.productList
  //   let count = 0
  //   if (productList) {
  //     for (let i in productList) {
  //       const product = productList[i]
  //       count += product.count
  //     }
  //   }
  //   return count
  // })

  // const price = computed(() => {  // 价格总计 computed
  //   const productList = cartList[shopId]?.productList
  //   let count = 0
  //   if (productList) {
  //     for (let i in productList) {
  //       const product = productList[i]
  //       if (product.check) {
  //         count += (product.count * product.price)
  //       }
  //     }
  //   }
  //   return count.toFixed(2)
  // })

  // const allChecked = computed(() => {  // 全选按钮状态 computed
  //   const productList = cartList[shopId]?.productList
  //   let result = true
  //   if (productList) {
  //     for (let i in productList) {
  //       const product = productList[i]
  //       if (product.count > 0 && !product.check) {
  //         result = false
  //       }
  //     }
  //   }
  //   return result
  // })

  const changeCartItemCheck = (shopId, productId) => {  // 修改购物车选中按钮方法
    store.commit('changeCartItemCheck', { shopId,  productId })
  }

  const cleanCartProducts = (shopId) => {  // 清空购物车逻辑
    store.commit('cleanCartProducts', { shopId })
  }

  const setCartItemsChecked = (shopId) => {  // 设置全选
    store.commit('setCartItemsChecked', { shopId })
  }

  return { 
    productList, calculations,
    changeCartItemInfo, changeCartItemCheck, cleanCartProducts, setCartItemsChecked
  }
}

const toggleCartEffect = () => {  // 隐藏/展示 购物车逻辑
  const showCart = ref(false)
  const handleCartShowChange = () => {
    showCart.value = !showCart.value
  }

  return { showCart, handleCartShowChange }
}

export default {
  name: 'Cart',
  setup() {
    const route = useRoute()
    const shopId = route.params.id

    const { showCart, handleCartShowChange } = toggleCartEffect()

    const { 
      productList, calculations,
      changeCartItemInfo, changeCartItemCheck, cleanCartProducts, setCartItemsChecked
    } = useCartEffect(shopId)

    return {
      productList, calculations, shopId, showCart,
      changeCartItemInfo, changeCartItemCheck, cleanCartProducts, setCartItemsChecked, handleCartShowChange
    }
  }
}
</script>

<style lang="scss" scoped>
  @import '../../styles/variables.scss';
  @import '../../styles/mixins.scss';
  .mask {
    position: fixed;
    left: 0;
    right: 0;
    bottom: 0;
    top: 0;
    background: rgba(0, 0, 0, .5);
    z-index: 1;
  }
  .cart {
    position: absolute;
    left: 0;
    right: 0;
    bottom: 0;
    background-color: #fff;
    z-index: 2;
  }
  .check {
    line-height: .5rem;
    display: flex;
    box-sizing: border-box;
    height: .5rem;
    border-top: .01rem solid $content-bgColor;
    &_icon {
      width: .84rem;
      position: relative;
      img {
        display: block;
        margin: .12rem auto;
        width: .28rem;
        height: .26rem;
      }
      &_tag {
        padding: 0 .04rem;
        position: absolute;
        left: .46rem;
        top: .04rem;
        min-width: .2rem;
        height: .2rem;
        line-height: .2rem;
        border-radius: .1rem;
        background: $hightlight-fontColor;
        font-size: .12rem;
        text-align: center;
        color: $bgColor;
        transform: scale(.5);
        transform-origin: left center;
      }
    }
    &_info {
      flex: 1;
      color: $content-fontcolor;
      font-size: $content-fontcolor;
      &_price {
        color: $hightlight-fontColor;
        font-size: .18rem;
      }
    }
    &_btn {
      width: .98rem;
      font-size: .14rem;
      text-align: center;
      background: #4fb0f9;
      a {
        color: $bgColor;
        text-decoration: none;
      }
    }
  }
  .product {
    flex: 1;
    overflow-y: scroll;
    background: #fff;
    &_header {
      display: flex;
      line-height: .52rem;
      border-bottom: .01rem solid #f1f1f1;
      font-size: .14rem;
      color: #333;
      &_all {
        width: .64rem;
        margin-left: .16rem;
      }
      &_icon {
        display: inline-block;
        color: #0091ff;
      }
      &_clear {
        flex: 1;
        margin-right: .16rem;
        text-align: right;
        &_btn {
          display: inline-block;
        }
      }
    }
    &_item {
      display: flex;
      position: relative;
      padding: .12rem 0;
      margin: 0 .16rem;
      border-bottom: .01rem solid #f1f1f1;
      img {
        width: .46rem;
        height: .46rem;
        margin-right: .16rem;                                                                                                                                                           
      }
      &_detail {
        overflow: hidden;
      }
      &_title {
        margin: 0;
        line-height: .2rem;
        font-size: .14rem;
        color: #333;
        @include ellipses;
      }
      &_price {
        margin: .06rem 0 0 0;
        line-height: .2rem;
        font-size: .14rem;
        color: $hightlight-fontColor;
      }
      &_yen {
        font-size: .12rem;
      }
      &_origin {
        margin-left: .06rem;
        line-height: .2rem;
        font-size: .12rem;
        color: #999;
        text-decoration: line-through;
      }
      .product_number {
        position: absolute;
        right: 0;
        bottom: .26rem;
        &_minus,
        &_plus {
          display: inline-block;
          width: .2rem;
          height: .2rem;
          line-height: .16rem;
          border-radius: 50%;
          font-size: .2rem;
          text-align: center;
        }
        &_minus {
          border: .01rem solid $medium-fontColor;
          color: $medium-fontColor;
          margin-right: .05rem;
        }
        &_plus {
          margin-left: .05rem;
          color: $bgColor;
          background: $btn-bgColor;
        }
      }
      &_checked {
        color: #0091ff;
        font-size: .2rem;
        line-height: .5rem;
        margin-right: .2rem;
      }
    }
  }
</style>