<template>
  <div class="wrapper">
    <div class="search">
      <div class="search_back iconfont" @click="handleBackClick">&#xe677;</div>
      <div class="search_content">
        <span class="search_content_icon iconfont">&#xe632;</span>
        <input class="search_content_input" placeholder="请输入商品名称" />
      </div>
    </div>
    <ShopInfo :item="item" :hideBorder="true" v-show="item.imgUrl" />
    <Content :shopName="item.name" />
    <Cart />
  </div>
</template>

<script>
import { reactive, toRefs } from 'vue'
import { useRouter, useRoute } from 'vue-router'
import { get } from '../../utils/request'
import ShopInfo from '../../components/ShopInfo.vue'
import Content from './Content.vue'
import Cart from './Cart.vue'

const useShopInfoEffect = () => {  // 获取当前商铺信息
  const route = useRoute()
  const data = reactive({ item: {} })
  const getItemData = async () => {
    const result = await get(`/api/shop/${route.params.id}`)
    if (result?.errno === 0 && result?.data) {
      data.item = result.data
    }
  }
  const { item } = toRefs(data)
  return { item, getItemData }
}

const useBackRouterEffect = () => {  // 点击回退逻辑
  const router = useRouter()
  const handleBackClick = () => {
    router.back()
  }
  
  return { handleBackClick }
}

export default {
  name: 'Shop',
  components: {
    ShopInfo,
    Content,
    Cart
  },
  setup() {
    const { item, getItemData } = useShopInfoEffect()
    const { handleBackClick } = useBackRouterEffect()
    getItemData()

    return { item, handleBackClick }
  }
}
</script>

<style lang="scss" scoped>
  @import '../../styles/variables.scss';
  .wrapper {
    padding: 0 .18rem;
  }
  .search {
    display: flex;
    margin: .14rem 0 .04rem 0;
    line-height: .32rem;
    &_back {
      width: .3rem;
      color: #b6b6b6;
    }
    &_content {
      display: flex;
      flex: 1;
      background-color: $search-bgColor;
      border-radius: .16rem;
      &_icon {
        width: .44rem;
        color: $search-fontColor;
        text-align: center;
      }
      &_input {
        padding-right: .2rem;
        display: block;
        width: 100%;
        height: .32rem;
        outline: none;
        border: none;
        background: none;
        color: $content-fontcolor;
        font-size: .14rem;
        &::placeholder {
          color: $content-fontcolor;
        }
      }
    }
  }
</style>